import{_ as e,o as d,c as o,ai as a}from"./chunks/framework.2e-g_11C.js";const u=JSON.parse('{"title":"Computed Fields","description":"","frontmatter":{},"headers":[],"relativePath":"computed-fields.md","filePath":"computed-fields.md"}'),r={name:"computed-fields.md"};function c(i,t,s,n,l,h){return d(),o("div",null,[...t[0]||(t[0]=[a(`<h1 id="computed-fields" tabindex="-1">Computed Fields <a class="header-anchor" href="#computed-fields" aria-label="Permalink to “Computed Fields”">​</a></h1><p>The Computed Interface allows you to automatically calculate field values based on other fields using templates and expressions. The calculation happens on the client side in real-time.</p><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to “Configuration”">​</a></h2><p>To set up a computed field:</p><ol><li>Go to <strong>Settings</strong>, create a new field with type string or number.</li><li>In the <strong>Interface</strong> panel, choose <strong>Computed</strong> interface. There are 8 options: <ol><li><strong>Template</strong>: Similar to M2M interface, determine how the field is calculated. Learn more about syntax in the next section.</li><li><strong>Field Mode</strong>: Choose how the value is displayed. <ul><li><strong>null</strong>: Default option. Show an input with the computed value but still allow manual editing.</li><li><strong>Display Only</strong>: Show the computed value but will not save it to the database. Usually used for alias fields.</li><li><strong>Read Only</strong>: Show an input with the computed value and disallow manual editing.</li></ul></li><li><strong>Prefix</strong>: a string to prefix the computed value.</li><li><strong>Suffix</strong>: a string to suffix the computed value.</li><li><strong>Custom CSS</strong>: a JSON object for inline style binding. Only works with <strong>Display Only</strong> and <strong>Read Only</strong> mode. You can use this option to customize the appearance of the computed value such as font size, color, etc. Example: <code>{&quot;color&quot;: &quot;red&quot;, &quot;font-size&quot;: &quot;20px&quot;}</code>.</li><li><strong>Debug Mode</strong>: Used for debugging the template. It will show an error message if the template is invalid. It will also log to console the result of each component of the template.</li><li><strong>Compute If Empty</strong>: Compute the value if the field is empty. This is useful if you want a value to be computed once such as the created date or a unique ID.</li><li><strong>Initial Compute</strong>: Compute the value when opening the form. This is useful if you want to compute a value based on the current date or other dynamic values.</li></ol></li></ol><h2 id="syntax" tabindex="-1">Syntax <a class="header-anchor" href="#syntax" aria-label="Permalink to “Syntax”">​</a></h2><p>The template consists of 2 elements: <strong>plain strings</strong> &amp; <strong>expressions</strong>.</p><ul><li><strong>Plain</strong> strings are string literal, often used for text interpolation.</li><li><strong>Expressions</strong> can contains operators, field names, numbers &amp; strings. They must be enclosed by <code>&amp;#123;&amp;#123;</code> and <code>&amp;#125;&amp;#125;</code>.</li></ul><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to “Examples”">​</a></h2><p>Sum 2 numbers:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&amp;#123;&amp;#123; SUM(a, b) &amp;#125;&amp;#125;</span></span></code></pre></div><p>Multiply 2 numbers:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&amp;#123;&amp;#123; MULTIPLY(a, b) &amp;#125;&amp;#125;</span></span></code></pre></div><p>Convert string to slug:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&amp;#123;&amp;#123; SLUG(title) &amp;#125;&amp;#125;</span></span></code></pre></div><p>Text interpolation:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>/&amp;#123;&amp;#123; SLUG(title) &amp;#125;&amp;#125;-&amp;#123;&amp;#123; id &amp;#125;&amp;#125;</span></span></code></pre></div><p>Complex calculation:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&amp;#123;&amp;#123; SUM(MULTIPLY(2, x), b) &amp;#125;&amp;#125;</span></span></code></pre></div><p>Literal strings are enclosed by double quotes (<code>&quot;</code>):</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&amp;#123;&amp;#123; CONCAT(file, &quot;.txt&quot;) &amp;#125;&amp;#125;</span></span></code></pre></div><p>Use <code>.</code> to access nested fields in M2O or M2M fields:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&amp;#123;&amp;#123; CONCAT(CONCAT(user.first_name, &quot; &quot;), user.last_name) &amp;#125;&amp;#125;</span></span></code></pre></div><p>Combine <code>AT</code>, <code>FIRST</code>, <code>LAST</code>, <code>JSON_GET</code> to access nested fields in O2M or JSON fields:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&amp;#123;&amp;#123; JSON_GET(AT(products, 0), &quot;name&quot;) &amp;#125;&amp;#125;</span></span>
<span class="line"><span>&amp;#123;&amp;#123; JSON_GET(LAST(products), &quot;price&quot;) &amp;#125;&amp;#125;</span></span></code></pre></div><p><strong>Note</strong>: For M2O, O2M, M2M fields, you can only access the fields of the direct relation. For example, if you have a <code>user</code> field that is a M2O relation to the <code>users</code> collection, you can only access the fields of the <code>users</code> collection. You cannot access the fields of the <code>roles</code> collection even though the <code>users</code> collection has a M2O relation to the <code>roles</code> collection. On the other hand, JSON fields have no such limitation!</p><h2 id="available-operators" tabindex="-1">Available operators <a class="header-anchor" href="#available-operators" aria-label="Permalink to “Available operators”">​</a></h2><h3 id="type-conversion" tabindex="-1">Type conversion <a class="header-anchor" href="#type-conversion" aria-label="Permalink to “Type conversion”">​</a></h3><table tabindex="0"><thead><tr><th>Operator</th><th>Description</th></tr></thead><tbody><tr><td><code>INT(a)</code></td><td>convert to integer</td></tr><tr><td><code>FLOAT(a)</code></td><td>convert to float</td></tr><tr><td><code>STRING(a)</code></td><td>convert to string</td></tr><tr><td><code>DATE(a)</code></td><td>convert to date</td></tr></tbody></table><h3 id="format" tabindex="-1">Format <a class="header-anchor" href="#format" aria-label="Permalink to “Format”">​</a></h3><table tabindex="0"><thead><tr><th>Operator</th><th>Description</th></tr></thead><tbody><tr><td><code>SLUG(a)</code></td><td>transform string to slug (e.g. &quot;This is a title&quot; → &quot;this-is-a-title&quot;)</td></tr><tr><td><code>CURRENCY(a)</code></td><td>format number to currency (e.g. 3000 → &quot;3,000&quot;)</td></tr></tbody></table><h3 id="date" tabindex="-1">Date <a class="header-anchor" href="#date" aria-label="Permalink to “Date”">​</a></h3><table tabindex="0"><thead><tr><th>Operator</th><th>Description</th></tr></thead><tbody><tr><td><code>DATE_ISO(a)</code></td><td>transform date or date-like object to ISO string</td></tr><tr><td><code>DATE_UTC(a)</code></td><td>transform date or date-like object to UTC string</td></tr><tr><td><code>DATE_STR(a)</code></td><td>transform date or date-like object to string with format &quot;YYYY-MM-DD&quot;</td></tr><tr><td><code>TIME_STR(a)</code></td><td>transform date or date-like object to string with format &quot;HH:mm:ss&quot;</td></tr><tr><td><code>YEAR(a)</code></td><td>get year of a date object, similar to <code>getFullYear</code></td></tr><tr><td><code>MONTH(a)</code></td><td>get month of a date object, similar to <code>getMonth</code></td></tr><tr><td><code>GET_DATE(a)</code></td><td>get date of a date object, similar to <code>getDate</code></td></tr><tr><td><code>DAY(a)</code></td><td>get day of a date object, similar to <code>getDay</code></td></tr><tr><td><code>HOURS(a)</code></td><td>get hours of a date object, similar to <code>getHours</code></td></tr><tr><td><code>MINUTES(a)</code></td><td>get minutes of a date object, similar to <code>getMinutes</code></td></tr><tr><td><code>SECONDS(a)</code></td><td>get seconds of a date object, similar to <code>getSeconds</code></td></tr><tr><td><code>TIME(a)</code></td><td>get time of a date object, similar to <code>getTime</code></td></tr><tr><td><code>LOCALE_STR(a, locale, options)</code></td><td>transform date or date-like object to string with locale format, <code>options</code> is a stringified JSON object. Example: <code>LOCALE_STR(&quot;2023-01-01&quot;, &quot;en-US&quot;, &quot;&amp;#123;\\&quot;weekday\\&quot;: \\&quot;long\\&quot;, \\&quot;year\\&quot;: \\&quot;numeric\\&quot;, \\&quot;month\\&quot;: \\&quot;long\\&quot;, \\&quot;day\\&quot;: \\&quot;numeric\\&quot;&amp;#125;&quot;)</code> returns &quot;Sunday, January 1, 2023&quot;.</td></tr></tbody></table><h3 id="arithmetic" tabindex="-1">Arithmetic <a class="header-anchor" href="#arithmetic" aria-label="Permalink to “Arithmetic”">​</a></h3><table tabindex="0"><thead><tr><th>Operator</th><th>Description</th></tr></thead><tbody><tr><td><code>ABS(a)</code></td><td>absolute</td></tr><tr><td><code>SQRT(a)</code></td><td>square root</td></tr><tr><td><code>SUM(a)</code></td><td>sum an array of numbers</td></tr><tr><td><code>SUM(a, b)</code></td><td>a + b</td></tr><tr><td><code>AVERAGE(a)</code></td><td>average value of an array of number</td></tr><tr><td><code>SUBTRACT(a, b)</code></td><td>a - b</td></tr><tr><td><code>MULTIPLY(a, b)</code></td><td>a * b</td></tr><tr><td><code>DIVIDE(a, b)</code></td><td>a / b</td></tr><tr><td><code>REMAINDER(a, b)</code></td><td>a % b</td></tr><tr><td><code>CEIL(a)</code></td><td>returns the smallest integer greater than or equal to <code>a</code>.</td></tr><tr><td><code>FLOOR(a)</code></td><td>returns the largest integer less than or equal to <code>a</code>.</td></tr><tr><td><code>ROUND(a)</code></td><td>rounds to the nearest integer.</td></tr><tr><td><code>ROUND(a, n)</code></td><td>rounds number <code>a</code> to <code>n</code> number of decimals, (<code>ROUND(1.23, 1) = 1.2</code>).</td></tr><tr><td><code>MAX(a, b)</code></td><td>max value between <code>a</code> and <code>b</code>.</td></tr><tr><td><code>MAX(arr)</code></td><td>max value of an array of numbers.</td></tr><tr><td><code>MIN(a, b)</code></td><td>min value between <code>a</code> and <code>b</code>.</td></tr><tr><td><code>MIN(arr)</code></td><td>min value of an array of numbers.</td></tr><tr><td><code>POWER(a, b)</code></td><td>a^b</td></tr><tr><td><code>EXP(a)</code></td><td>returns <code>e^a</code>, where <code>e</code> is Euler&#39;s number.</td></tr><tr><td><code>LOG(a)</code></td><td>returns the natural logarithm (base <code>e</code>) of <code>a</code>.</td></tr></tbody></table><h3 id="string" tabindex="-1">String <a class="header-anchor" href="#string" aria-label="Permalink to “String”">​</a></h3><table tabindex="0"><thead><tr><th>Operator</th><th>Description</th></tr></thead><tbody><tr><td><code>STR_LEN(str)</code></td><td>length of string (deprecated, use <code>LENGTH</code> instead)</td></tr><tr><td><code>LENGTH(str)</code></td><td>length of string</td></tr><tr><td><code>FIRST(str)</code></td><td>first character of string</td></tr><tr><td><code>LAST(str)</code></td><td>last character of string</td></tr><tr><td><code>REVERSE(str)</code></td><td>reverse string</td></tr><tr><td><code>LOWER(str)</code></td><td>to lower case</td></tr><tr><td><code>UPPER(str)</code></td><td>to upper case</td></tr><tr><td><code>TRIM(str)</code></td><td>removes whitespace at the beginning and end of string.</td></tr><tr><td><code>CONCAT(strA, strB)</code></td><td>concat 2 strings <code>strA</code> and <code>strB</code>.</td></tr><tr><td><code>LEFT(str, count)</code></td><td>extract <code>count</code> characters from the beginning of the string <code>str</code>.</td></tr><tr><td><code>RIGHT(str, count)</code></td><td>extract <code>count</code> characters from the end of the string <code>str</code>.</td></tr><tr><td><code>MID(str, startAt, count)</code></td><td>extract <code>count</code> characters from <code>startAt</code> position of the string <code>str</code>.</td></tr><tr><td><code>ENCODE_URL_COMPONENT(str)</code></td><td>encode string to URL component.</td></tr><tr><td><code>REPT(str, count)</code></td><td>repeat string <code>count</code> times.</td></tr><tr><td><code>JOIN(arr, separator)</code></td><td>join an array of strings with <code>separator</code>.</td></tr><tr><td><code>SPLIT(str, separator)</code></td><td>split string <code>str</code> by <code>separator</code> to an array of strings.</td></tr><tr><td><code>SEARCH(str, keyword)</code></td><td>search <code>keyword</code> in <code>str</code> and return the position of the first occurrence. Return -1 if not found.</td></tr><tr><td><code>SEARCH(str, keyword, startAt)</code></td><td>search <code>keyword</code> in <code>str</code> and return the position of the first occurrence after <code>startAt</code>. Return -1 if not found.</td></tr><tr><td><code>SUBSTITUTE(str, old, new)</code></td><td>replace all occurrences of <code>old</code> in <code>str</code> with <code>new</code>.</td></tr><tr><td><code>AT(str, index)</code></td><td>get character at <code>index</code> of <code>str</code>.</td></tr><tr><td><code>INDEX_OF(str, keyword)</code></td><td>get the position of the first occurrence of <code>keyword</code> in <code>str</code>. Return -1 if not found.</td></tr><tr><td><code>INCLUDES(str, keyword)</code></td><td>check if <code>str</code> contains <code>keyword</code>.</td></tr><tr><td><code>SLICE(str, startAt, endAt)</code></td><td>extract a part of <code>str</code> from <code>startAt</code> to <code>endAt</code>. <code>endAt</code> can be negative. Similar to <code>slice</code> method of <code>String</code>.</td></tr></tbody></table><h3 id="boolean" tabindex="-1">Boolean <a class="header-anchor" href="#boolean" aria-label="Permalink to “Boolean”">​</a></h3><table tabindex="0"><thead><tr><th>Operator</th><th>Description</th></tr></thead><tbody><tr><td><code>NULL(a)</code></td><td>check is null</td></tr><tr><td><code>NOT_NULL(a)</code></td><td>check is not null</td></tr><tr><td><code>NOT(a)</code></td><td>logical NOT</td></tr><tr><td><code>EQUAL(a, b)</code></td><td>a = b</td></tr><tr><td><code>NOT_EQUAL(a, b)</code></td><td>a &lt;&gt; b</td></tr><tr><td><code>GT(a, b)</code></td><td>a &gt; b</td></tr><tr><td><code>GTE(a, b)</code></td><td>a &gt;= b</td></tr><tr><td><code>LT(a, b)</code></td><td>a &lt; b</td></tr><tr><td><code>LTE(a, b)</code></td><td>a &lt;= b</td></tr><tr><td><code>AND(a, b)</code></td><td>logical AND</td></tr><tr><td><code>OR(a, b)</code></td><td>logical OR</td></tr></tbody></table><h3 id="array" tabindex="-1">Array <a class="header-anchor" href="#array" aria-label="Permalink to “Array”">​</a></h3><table tabindex="0"><thead><tr><th>Operator</th><th>Description</th></tr></thead><tbody><tr><td><code>ARRAY_LEN(a)</code></td><td>length of array (deprecated, use <code>LENGTH</code> instead)</td></tr><tr><td><code>LENGTH(a)</code></td><td>length of array</td></tr><tr><td><code>FIRST(a)</code></td><td>first element of array</td></tr><tr><td><code>LAST(a)</code></td><td>last element of array</td></tr><tr><td><code>REVERSE(a)</code></td><td>reverse array</td></tr><tr><td><code>CONCAT(a, b)</code></td><td>concat 2 arrays <code>a</code> and <code>b</code>.</td></tr><tr><td><code>AT(a, index)</code></td><td>get element at <code>index</code> of <code>a</code>.</td></tr><tr><td><code>INDEX_OF(a, element)</code></td><td>get the position of the first occurrence of <code>element</code> in <code>a</code>. Return -1 if not found.</td></tr><tr><td><code>INCLUDES(a, element)</code></td><td>check if <code>a</code> contains <code>element</code>.</td></tr><tr><td><code>SLICE(a, startAt, endAt)</code></td><td>extract a part of <code>a</code> from <code>startAt</code> to <code>endAt</code>. <code>endAt</code> can be negative. Similar to <code>slice</code> method of <code>Array</code>.</td></tr><tr><td><code>MAP(a, expression)</code></td><td>apply <code>expression</code> to each element of <code>a</code> and return a new array, each element of <code>a</code> must be an object. Example: <code>MAP(products, MULTIPLY(price, quantity))</code> returns an array of total price of each product.</td></tr><tr><td><code>FILTER(a, expression)</code></td><td>filter <code>a</code> with <code>expression</code> and return a new array, each element of <code>a</code> must be an object. Example: <code>FILTER(products, GT(stock, 0))</code> returns an array of products that are in stock.</td></tr><tr><td><code>SORT(a, expression)</code></td><td>sort <code>a</code> with <code>expression</code> and return a new array, each element of <code>a</code> must be an object. Example: <code>SORT(products, price)</code> returns an array of products sorted by price.</td></tr></tbody></table><h3 id="json" tabindex="-1">JSON <a class="header-anchor" href="#json" aria-label="Permalink to “JSON”">​</a></h3><table tabindex="0"><thead><tr><th>Operator</th><th>Description</th></tr></thead><tbody><tr><td><code>JSON_GET(a, key)</code></td><td>get value of <code>key</code> in JSON object <code>a</code>.</td></tr><tr><td><code>JSON_PARSE(a)</code></td><td>parse string <code>a</code> to JSON object.</td></tr><tr><td><code>JSON_STRINGIFY(a)</code></td><td>stringify JSON object <code>a</code>.</td></tr></tbody></table><h3 id="relational" tabindex="-1">Relational <a class="header-anchor" href="#relational" aria-label="Permalink to “Relational”">​</a></h3><table tabindex="0"><thead><tr><th>Operator</th><th>Description</th></tr></thead><tbody><tr><td><code>ASUM(a, b)</code></td><td>Aggregated sum of O2M field. For example: calculate shopping cart total price with <code>ASUM(products, MULTIPLY(price, quantity))</code>, where <code>products</code> is the O2M field in the shopping cart and <code>price</code> &amp; <code>quantity</code> are 2 fields of <code>products</code>.</td></tr><tr><td><code>AMIN(a, b)</code></td><td>Aggregated min of O2M field.</td></tr><tr><td><code>AMAX(a, b)</code></td><td>Aggregated max of O2M field.</td></tr><tr><td><code>AAVG(a, b)</code></td><td>Aggregated average of O2M field.</td></tr><tr><td><code>AMUL(a, b)</code></td><td>Aggregated multiplication of O2M field.</td></tr><tr><td><code>AAND(a, b)</code></td><td>Aggregated logical AND of O2M field. Only return <code>true</code> if all values are <code>true</code>.</td></tr><tr><td><code>AOR(a, b)</code></td><td>Aggregated logical OR of O2M field. Only return <code>true</code> if at least one value is <code>true</code>.</td></tr><tr><td><code>ACOUNT(a, b)</code></td><td>Aggregated count of O2M field. Only count true values. For example: count the number of products that are in stock with <code>ACOUNT(products, GT(stock, 0))</code>, where <code>stock</code> is a field of <code>products</code>.</td></tr></tbody></table><h3 id="condition" tabindex="-1">Condition <a class="header-anchor" href="#condition" aria-label="Permalink to “Condition”">​</a></h3><table tabindex="0"><thead><tr><th>Operator</th><th>Description</th></tr></thead><tbody><tr><td><code>IF(A, B, C)</code></td><td>return <code>B</code> if <code>A</code> is <code>true</code>, otherwise <code>C</code></td></tr><tr><td><code>IFS(A1, B1, A2, B2, ..., An, Bn)</code></td><td>return <code>Bi</code> if <code>Ai</code> is the first to be <code>true</code>, if none of <code>Ai</code> is <code>true</code>, return <code>null</code></td></tr></tbody></table><h3 id="others" tabindex="-1">Others <a class="header-anchor" href="#others" aria-label="Permalink to “Others”">​</a></h3><table tabindex="0"><thead><tr><th>Operator</th><th>Description</th></tr></thead><tbody><tr><td><code>RANGE(start, end, step)</code></td><td>create an array of numbers from <code>start</code> to <code>end</code> with <code>step</code> increment/decrement. Example: <code>RANGE(1, 10, 2)</code> returns <code>[1, 3, 5, 7, 9]</code>.</td></tr></tbody></table><h2 id="dynamic-variables" tabindex="-1">Dynamic Variables <a class="header-anchor" href="#dynamic-variables" aria-label="Permalink to “Dynamic Variables”">​</a></h2><p>There are 2 dynamic variables available that you can use in the expressions:</p><ul><li><code>$NOW</code>: return the current Date object. Example: <code>&amp;#123;&amp;#123; YEAR($NOW) &amp;#125;&amp;#125;</code> returns the current year.</li><li><code>$CURRENT_USER</code>: return the current user&#39;s id. Example: <code>&amp;#123;&amp;#123; EQUAL($CURRENT_USER, user) &amp;#125;&amp;#125;</code> checks if the <code>user</code> field is the current user.</li></ul>`,52)])])}const b=e(r,[["render",c]]);export{u as __pageData,b as default};
